@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between mb-0 p-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isActive = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isActive && !isCompleted;

            <li class="step-item text-center flex-fill @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn btn-link p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block mt-1 text-success fw-semibold">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isActive ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@step</span>
