@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        @if (CanRemove)
        {
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @Index</h6>
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            </div>
        }
        else
        {
            <h6 class="mb-2">Position @Index</h6>
        }

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Company" @onchange="e => { Company = e.Value?.ToString() ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Title" @onchange="e => { Title = e.Value?.ToString() ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate.ToString("yyyy-MM-dd")" @onchange="OnStartDateChanged" />
            </div>
            <div class="col-md-4">
                <div class="form-check mt-4 pt-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@IsCurrent" @onchange="OnCurrentChanged" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-md-4">
                @if (!IsCurrent)
                {
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(EndDate?.ToString("yyyy-MM-dd") ?? "")" @onchange="OnEndDateChanged" />
                }
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @onchange="e => { Description = e.Value?.ToString() ?? ""; NotifyChanged(); }">@Description</textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; } = DateTime.Today;
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnEntryChanged { get; set; }

    public record WorkEntryData(int Index, string Company, string Title, DateTime StartDate, DateTime? EndDate, bool IsCurrent, string Description);

    private void NotifyChanged()
    {
        OnEntryChanged.InvokeAsync(new WorkEntryData(Index, Company, Title, StartDate, IsCurrent ? null : EndDate, IsCurrent, Description));
    }

    private void OnStartDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d)) StartDate = d;
        NotifyChanged();
    }

    private void OnEndDateChanged(ChangeEventArgs e)
    {
        EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null;
        NotifyChanged();
    }

    private void OnCurrentChanged(ChangeEventArgs e)
    {
        IsCurrent = (bool)(e.Value ?? false);
        if (IsCurrent) EndDate = null;
        NotifyChanged();
    }
}

