@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@FullName" @onchange="e => FullName = e.Value?.ToString() ?? "" " />
    </div>
