+        <label class="form-label">Address <span class="text-danger">*</span></label>
+        <input type="text" class="form-control" value="@Address" @onchange="e => Address = e.Value?.ToString() ?? "" " />
+    </div>
+</div>
+
+<div class="d-flex justify-content-end mt-4">
+    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
+        @if (isValidating)
+        {
+            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+        }
+        Next
+    </button>
+</div>
+
+@code {
+    [Parameter] public string FullName { get; set; } = "";
+    [Parameter] public string Email { get; set; } = "";
+    [Parameter] public string Phone { get; set; } = "";
+    [Parameter] public string Address { get; set; } = "";
+    [Parameter] public EventCallback<PersonalInfoData> OnNext { get; set; }
+    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }
+
+    public record PersonalInfoData(string FullName, string Email, string Phone, string Address);
+
+    private string? ErrorMessage;
+    private bool emailInvalid;
+    private bool isValidating;
+
+    private async Task HandleNext()
+    {
+        ErrorMessage = null;
+        emailInvalid = false;
+
+        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
+            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
+        {
+            ErrorMessage = "All fields are required.";
+            return;
+        }
+
+        if (ValidateEmail is not null)
+        {
+            isValidating = true;
+            StateHasChanged();
+
+            var valid = await ValidateEmail(Email);
+            isValidating = false;
+
+            if (!valid)
+            {
+                emailInvalid = true;
+                ErrorMessage = "The email address is not valid.";
+                return;
+            }
+        }
+
+        await OnNext.InvokeAsync(new PersonalInfoData(FullName, Email, Phone, Address));
+    }
+}
+

