@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var entry = Entries[i];
    var idx = i;
    <WorkEntryForm
        Index="@(idx + 1)"
        Company="@entry.Company"
        Title="@entry.Title"
        StartDate="@entry.StartDate"
        EndDate="@entry.EndDate"
        IsCurrent="@(!entry.EndDate.HasValue && entry.Company != "")"
        Description="@entry.Description"
        CanRemove="@(Entries.Count > 1)"
        OnRemove="() => RemoveEntry(idx)"
        OnEntryChanged="OnEntryChanged" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryState> Entries { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<List<WorkEntryState>> OnNext { get; set; }

    public class WorkEntryState
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryState());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void OnEntryChanged(WorkEntryForm.WorkEntryData data)
    {
        var idx = data.Index - 1;
        if (idx >= 0 && idx < Entries.Count)
        {
            Entries[idx].Company = data.Company;
            Entries[idx].Title = data.Title;
            Entries[idx].StartDate = data.StartDate;
            Entries[idx].EndDate = data.EndDate;
            Entries[idx].Description = data.Description;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync(Entries);
    }
}

