@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12" maxlength="@MaxLength" @oninput="OnInput" value="@CoverLetter"></textarea>
    <div class="form-text text-end">@(CoverLetter?.Length ?? 0) / @MaxLength characters</div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<string> OnNext { get; set; }

    private void OnInput(ChangeEventArgs e)
    {
        var text = e.Value?.ToString() ?? "";
        CoverLetter = text.Length > MaxLength ? text[..MaxLength] : text;
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync(CoverLetter);
    }
}

