@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply

<h4 class="mb-4">Review Your Application</h4>

@* Personal Info *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-6"><strong>Name:</strong> @FullName</div>
            <div class="col-md-6"><strong>Email:</strong> @Email</div>
            <div class="col-md-6"><strong>Phone:</strong> @Phone</div>
            <div class="col-md-6"><strong>Address:</strong> @Address</div>
        </div>
    </div>
</div>

@* Work History *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-child-no-border">
                <div><strong>@entry.Title</strong> at @entry.Company</div>
                <div class="text-muted small">
                    @entry.StartDate.ToString("MMM yyyy") &ndash;
                    @(entry.EndDate.HasValue ? entry.EndDate.Value.ToString("MMM yyyy") : "Present")
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <div class="mt-1">@entry.Description</div>
                }
            </div>
        }
    </div>
</div>

@* References *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
            </div>
        }
    </div>
</div>

@* Cover Letter *@
<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Submit Application
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkHistoryStep.WorkEntryState> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferencesStep.ReferenceState> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
}

