@page "/apply"
@rendermode InteractiveServer
@namespace sv_20e5cd4a6e19405eb5a61abdc64d083b.Components.Pages.Apply
@using sv_20e5cd4a6e19405eb5a61abdc64d083b.Services

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    @if (submitted)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="bg-success text-white rounded-circle d-inline-flex align-items-center justify-content-center" style="width:64px;height:64px;font-size:2rem;">✓</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
            <p class="text-muted">Thank you for applying. We'll be in touch soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

        <div class="mt-4">
            @switch (currentStep)
            {
                case 1:
                    <PersonalInfoStep
                        FullName="@fullName"
                        Email="@email"
                        Phone="@phone"
                        Address="@address"
                        ValidateEmail="ValidateEmail"
                        OnNext="HandlePersonalInfoNext" />
                    break;

                case 2:
                    <WorkHistoryStep
                        Entries="workEntries"
                        OnBack="() => currentStep = 1"
                        OnNext="HandleWorkHistoryNext" />
                    break;

                case 3:
                    <ReferencesStep
                        References="references"
                        OnBack="() => currentStep = 2"
                        OnNext="HandleReferencesNext" />
                    break;

                case 4:
                    <CoverLetterStep
                        CoverLetter="@coverLetter"
                        OnBack="() => currentStep = 3"
                        OnNext="HandleCoverLetterNext" />
                    break;

                case 5:
                    <ReviewStep
                        FullName="@fullName"
                        Email="@email"
                        Phone="@phone"
                        Address="@address"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        IsSubmitting="isSubmitting"
                        ErrorMessage="@submitError"
                        OnBack="() => currentStep = 4"
                        OnSubmit="HandleSubmit"
                        OnEdit="GoToStep" />
                    break;
            }
        </div>
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private bool submitted;
    private int applicationId;
    private bool isSubmitting;
    private string? submitError;

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkHistoryStep.WorkEntryState> workEntries = new() { new() };

    // Step 3
    private List<ReferencesStep.ReferenceState> references = new() { new(), new() };

    // Step 4
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step))
            currentStep = step;
    }

    private Task<bool> ValidateEmail(string emailToValidate)
        => ApplicationService.ValidateEmailAsync(emailToValidate);

    private void HandlePersonalInfoNext(PersonalInfoStep.PersonalInfoData data)
    {
        fullName = data.FullName;
        email = data.Email;
        phone = data.Phone;
        address = data.Address;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleWorkHistoryNext(List<WorkHistoryStep.WorkEntryState> entries)
    {
        workEntries = entries;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleReferencesNext(List<ReferencesStep.ReferenceState> refs)
    {
        references = refs;
        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new Models.JobApplication(
                new Models.PersonalInfo(fullName, email, phone, address),
                new Models.WorkHistory(
                    workEntries.Select(e => new Models.WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList()
                ),
                references.Select(r => new Models.Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

