+                    break;
+
+                case 2:
+                    <WorkHistoryStep
+                        Entries="workEntries"
+                        OnBack="() => currentStep = 1"
+                        OnNext="HandleWorkHistoryNext" />
+                    break;
+
+                case 3:
+                    <ReferencesStep
+                        References="references"
+                        OnBack="() => currentStep = 2"
+                        OnNext="HandleReferencesNext" />
+                    break;
+
+                case 4:
+                    <CoverLetterStep
+                        CoverLetter="@coverLetter"
+                        OnBack="() => currentStep = 3"
+                        OnNext="HandleCoverLetterNext" />
+                    break;
+
+                case 5:
+                    <ReviewStep
