+        fullName = data.FullName;
+        email = data.Email;
+        phone = data.Phone;
+        address = data.Address;
+        completedSteps.Add(1);
+        currentStep = 2;
+    }
+
+    private void HandleWorkHistoryNext(List<WorkHistoryStep.WorkEntryState> entries)
+    {
+        workEntries = entries;
+        completedSteps.Add(2);
+        currentStep = 3;
+    }
+
+    private void HandleReferencesNext(List<ReferencesStep.ReferenceState> refs)
+    {
+        references = refs;
+        completedSteps.Add(3);
+        currentStep = 4;
+    }
+
+    private void HandleCoverLetterNext(string text)
+    {
+        coverLetter = text;
+        completedSteps.Add(4);
+        currentStep = 5;
+    }
+
+    private async Task HandleSubmit()
+    {
+        isSubmitting = true;
+        submitError = null;
+
+        try
+        {
+            var application = new Models.JobApplication(
+                new Models.PersonalInfo(fullName, email, phone, address),
+                new Models.WorkHistory(
+                    workEntries.Select(e => new Models.WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList()
+                ),
+                references.Select(r => new Models.Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
+                coverLetter
+            );
+
+            applicationId = await ApplicationService.SubmitApplicationAsync(application);
+            completedSteps.Add(5);
+            submitted = true;
+        }
+        catch (Exception ex)
+        {
+            submitError = $"Submission failed: {ex.Message}. Please try again.";
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
+}
